proptest! {
    #![proptest_config(ProptestConfig { max_global_rejects: 65536, ..ProptestConfig::with_cases(256) })]
    #[test]
    fn fund_project_preserves_escrow_conservation(s in arb_state()) {
        let mut s = s;
        prop_assume!(escrow_conservation(&s));
        prop_assume!(treasury_monotonic(&s));
        prop_assume!(buyer_rep_counters_nonneg(&s));
        prop_assume!(provider_rep_counters_nonneg(&s));
        prop_assume!(buyer_attest_at_most_once(&s));
        prop_assume!(win_attest_at_most_once(&s));
        prop_assume!(single_milestone_in_flight(&s));
        prop_assume!(bid_writes_gated_by_window(&s));
        prop_assume!(bid_finalize_requires_committed_envelopes(&s));
        prop_assume!(time_windows_strictly_increasing(&s));
        prop_assume!(contract_value_set_on_award(&s));
        prop_assume!(escrow_locks_contract_value(&s));
        prop_assume!(fee_bps_bounded(&s));
        prop_assume!(rfp_buyer_immutable_after_open(&s));
        prop_assume!(treasury_initialized_after_init(&s));
        prop_assume!(bid_payout_chain_solana_only(&s));
        if fund_project(&mut s) {
            prop_assert!(escrow_conservation(&s),
                "escrow_conservation must hold after fund_project");
        }
    }
}

