#[derive(Debug, Clone)]
enum Op {
    InitTreasury(u64),
    RfpCreate(u64, u64, u64, u8, i64, i64, i64, u8, u8, u64, i64, i64, i64, i64, u8),
    RfpCloseBidding,
    RevealReserve(u64, u64),
    CommitBidInit(u64, u32, u32, u64, u8),
    DelegateBid,
    WriteBidChunk(u8, u32, u32),
    FinalizeBid,
    OpenRevealWindow,
    WithdrawBid,
    CloseWithdrawnBid,
    SelectBid(u64, u64, u8, u64, u8),
    FundProject,
    StartMilestone(u8),
    SubmitMilestone(u8),
    AcceptMilestone(u8),
    AutoReleaseMilestone(u8),
    RequestChanges(u8),
    RejectMilestone(u8),
    CancelWithNotice(u8),
    CancelWithPenalty(u8),
    CancelLateMilestone(u8),
    MarkBuyerGhosted,
    ExpireRfp,
    ResolveDispute(u8, u16),
    DisputeDefaultSplit(u8),
    AttestBuyerHistory,
    AttestWin,
}

fn arb_op() -> impl Strategy<Value = Op> {
    prop_oneof![
        (0u64..=u64::MAX).prop_map(|v| Op::InitTreasury(v)),
        ((0u64..=u64::MAX, 0u64..=u64::MAX, 0u64..=u64::MAX, 0u8..=u8::MAX, 0i64..=i64::MAX, 0i64..=i64::MAX, 0i64..=i64::MAX, 0u8..=u8::MAX, 0u8..=u8::MAX, 0u64..=u64::MAX, 0i64..=i64::MAX, 0i64..=i64::MAX), (0i64..=i64::MAX, 0i64..=i64::MAX, 0u8..=u8::MAX)).prop_map(|((rfp_nonce, buyer_encryption_pubkey, title_hash, category, bid_open_at, bid_close_at, reveal_close_at, bidder_visibility, buyer_visibility, reserve_price_commitment, funding_window_secs, review_window_secs), (dispute_cooloff_secs, cancel_notice_secs, max_iterations))| Op::RfpCreate(rfp_nonce, buyer_encryption_pubkey, title_hash, category, bid_open_at, bid_close_at, reveal_close_at, bidder_visibility, buyer_visibility, reserve_price_commitment, funding_window_secs, review_window_secs, dispute_cooloff_secs, cancel_notice_secs, max_iterations)),
        Just(Op::RfpCloseBidding),
        (0u64..=u64::MAX, 0u64..=u64::MAX).prop_map(|(reserve_amount, reserve_nonce)| Op::RevealReserve(reserve_amount, reserve_nonce)),
        (0u64..=u64::MAX, 0u32..=u32::MAX, 0u32..=u32::MAX, 0u64..=u64::MAX, 0u8..=u8::MAX).prop_map(|(commit_hash, buyer_envelope_len, provider_envelope_len, payout_destination, payout_chain)| Op::CommitBidInit(commit_hash, buyer_envelope_len, provider_envelope_len, payout_destination, payout_chain)),
        Just(Op::DelegateBid),
        (0u8..=u8::MAX, 0u32..=u32::MAX, 0u32..=u32::MAX).prop_map(|(envelope_kind, offset, data_len)| Op::WriteBidChunk(envelope_kind, offset, data_len)),
        Just(Op::FinalizeBid),
        Just(Op::OpenRevealWindow),
        Just(Op::WithdrawBid),
        Just(Op::CloseWithdrawnBid),
        (0u64..=u64::MAX, 0u64..=u64::MAX, 0u8..=u8::MAX, 0u64..=u64::MAX, 0u8..=u8::MAX).prop_map(|(winner_provider, contract_value, milestone_count, milestone_amounts_sum, milestone_amounts_all_positive)| Op::SelectBid(winner_provider, contract_value, milestone_count, milestone_amounts_sum, milestone_amounts_all_positive)),
        Just(Op::FundProject),
        (0u8..=u8::MAX).prop_map(|v| Op::StartMilestone(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::SubmitMilestone(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::AcceptMilestone(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::AutoReleaseMilestone(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::RequestChanges(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::RejectMilestone(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::CancelWithNotice(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::CancelWithPenalty(v)),
        (0u8..=u8::MAX).prop_map(|v| Op::CancelLateMilestone(v)),
        Just(Op::MarkBuyerGhosted),
        Just(Op::ExpireRfp),
        (0u8..=u8::MAX, 0u16..=u16::MAX).prop_map(|(milestone_index, split_to_provider_bps)| Op::ResolveDispute(milestone_index, split_to_provider_bps)),
        (0u8..=u8::MAX).prop_map(|v| Op::DisputeDefaultSplit(v)),
        Just(Op::AttestBuyerHistory),
        Just(Op::AttestWin),
    ]
}

fn apply_op(s: &mut State, op: &Op) -> bool {
    match op {
        Op::InitTreasury(authority) => init_treasury(s, *authority),
        Op::RfpCreate(rfp_nonce, buyer_encryption_pubkey, title_hash, category, bid_open_at, bid_close_at, reveal_close_at, bidder_visibility, buyer_visibility, reserve_price_commitment, funding_window_secs, review_window_secs, dispute_cooloff_secs, cancel_notice_secs, max_iterations) => rfp_create(s, *rfp_nonce, *buyer_encryption_pubkey, *title_hash, *category, *bid_open_at, *bid_close_at, *reveal_close_at, *bidder_visibility, *buyer_visibility, *reserve_price_commitment, *funding_window_secs, *review_window_secs, *dispute_cooloff_secs, *cancel_notice_secs, *max_iterations),
        Op::RfpCloseBidding => rfp_close_bidding(s),
        Op::RevealReserve(reserve_amount, reserve_nonce) => reveal_reserve(s, *reserve_amount, *reserve_nonce),
        Op::CommitBidInit(commit_hash, buyer_envelope_len, provider_envelope_len, payout_destination, payout_chain) => commit_bid_init(s, *commit_hash, *buyer_envelope_len, *provider_envelope_len, *payout_destination, *payout_chain),
        Op::DelegateBid => delegate_bid(s),
        Op::WriteBidChunk(envelope_kind, offset, data_len) => write_bid_chunk(s, *envelope_kind, *offset, *data_len),
        Op::FinalizeBid => finalize_bid(s),
        Op::OpenRevealWindow => open_reveal_window(s),
        Op::WithdrawBid => withdraw_bid(s),
        Op::CloseWithdrawnBid => close_withdrawn_bid(s),
        Op::SelectBid(winner_provider, contract_value, milestone_count, milestone_amounts_sum, milestone_amounts_all_positive) => select_bid(s, *winner_provider, *contract_value, *milestone_count, *milestone_amounts_sum, *milestone_amounts_all_positive),
        Op::FundProject => fund_project(s),
        Op::StartMilestone(milestone_index) => start_milestone(s, *milestone_index),
        Op::SubmitMilestone(milestone_index) => submit_milestone(s, *milestone_index),
        Op::AcceptMilestone(milestone_index) => accept_milestone(s, *milestone_index),
        Op::AutoReleaseMilestone(milestone_index) => auto_release_milestone(s, *milestone_index),
        Op::RequestChanges(milestone_index) => request_changes(s, *milestone_index),
        Op::RejectMilestone(milestone_index) => reject_milestone(s, *milestone_index),
        Op::CancelWithNotice(milestone_index) => cancel_with_notice(s, *milestone_index),
        Op::CancelWithPenalty(milestone_index) => cancel_with_penalty(s, *milestone_index),
        Op::CancelLateMilestone(milestone_index) => cancel_late_milestone(s, *milestone_index),
        Op::MarkBuyerGhosted => mark_buyer_ghosted(s),
        Op::ExpireRfp => expire_rfp(s),
        Op::ResolveDispute(milestone_index, split_to_provider_bps) => resolve_dispute(s, *milestone_index, *split_to_provider_bps),
        Op::DisputeDefaultSplit(milestone_index) => dispute_default_split(s, *milestone_index),
        Op::AttestBuyerHistory => attest_buyer_history(s),
        Op::AttestWin => attest_win(s),
    }
}

fn assert_all_properties(s: &State, context: &str) {
    assert!(escrow_conservation(s), "{} violated: escrow_conservation", context);
    assert!(treasury_monotonic(s), "{} violated: treasury_monotonic", context);
    assert!(buyer_rep_counters_nonneg(s), "{} violated: buyer_rep_counters_nonneg", context);
    assert!(provider_rep_counters_nonneg(s), "{} violated: provider_rep_counters_nonneg", context);
    assert!(buyer_attest_at_most_once(s), "{} violated: buyer_attest_at_most_once", context);
    assert!(win_attest_at_most_once(s), "{} violated: win_attest_at_most_once", context);
    assert!(single_milestone_in_flight(s), "{} violated: single_milestone_in_flight", context);
    assert!(bid_writes_gated_by_window(s), "{} violated: bid_writes_gated_by_window", context);
    assert!(bid_finalize_requires_committed_envelopes(s), "{} violated: bid_finalize_requires_committed_envelopes", context);
    assert!(time_windows_strictly_increasing(s), "{} violated: time_windows_strictly_increasing", context);
    assert!(contract_value_set_on_award(s), "{} violated: contract_value_set_on_award", context);
    assert!(escrow_locks_contract_value(s), "{} violated: escrow_locks_contract_value", context);
    assert!(fee_bps_bounded(s), "{} violated: fee_bps_bounded", context);
    assert!(rfp_buyer_immutable_after_open(s), "{} violated: rfp_buyer_immutable_after_open", context);
    assert!(treasury_initialized_after_init(s), "{} violated: treasury_initialized_after_init", context);
    assert!(bid_payout_chain_solana_only(s), "{} violated: bid_payout_chain_solana_only", context);
}

#[derive(Debug, Clone, Copy, PartialEq)]
enum Lifecycle {
    Uninitialized,
    Active,
}

fn lifecycle_transition(current: Lifecycle, op: &Op) -> Option<Lifecycle> {
    match (current, op) {
        (Lifecycle::Uninitialized, Op::InitTreasury(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::RfpCreate(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::RfpCloseBidding) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::RevealReserve(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::CommitBidInit(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::DelegateBid) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::WriteBidChunk(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::FinalizeBid) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::OpenRevealWindow) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::WithdrawBid) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::CloseWithdrawnBid) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::SelectBid(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::FundProject) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::StartMilestone(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::SubmitMilestone(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::AcceptMilestone(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::AutoReleaseMilestone(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::RequestChanges(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::RejectMilestone(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::CancelWithNotice(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::CancelWithPenalty(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::CancelLateMilestone(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::MarkBuyerGhosted) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::ExpireRfp) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::ResolveDispute(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::DisputeDefaultSplit(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::AttestBuyerHistory) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::AttestWin) => Some(Lifecycle::Active),
        _ => None, // transition not allowed in this state
    }
}

